'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { User, Clock, Heart, LogOut, Edit2, Save } from 'lucide-react';

export default function ProfilePage() {
  const { user, logout, login } = useAuth();
  const [history, setHistory] = useState<any[]>([]);
  const [favorites, setFavorites] = useState<any[]>([]);
  const [isEditingName, setIsEditingName] = useState(false);
  const [newName, setNewName] = useState(user?.name || '');
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (user) {
      fetch('http://localhost:5000/api/user/history', { credentials: 'include' })
        .then(res => res.json())
        .then(setHistory);
      fetch('http://localhost:5000/api/user/favorites', { credentials: 'include' })
        .then(res => res.json())
        .then(setFavorites);
    }
  }, [user]);

  const handleUpdateName = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('http://localhost:5000/api/user/profile', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: newName }),
        credentials: 'include'
      });
      const updatedUser = await res.json();
      login(updatedUser);
      setIsEditingName(false);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const removeFavorite = async (id: string) => {
    try {
      await fetch(`http://localhost:5000/api/user/favorites/${id}`, { method: 'DELETE', credentials: 'include' });
      setFavorites(favorites.filter(f => f.id !== id));
    } catch (err) {
      console.error(err);
    }
  };

  if (!user) return <div className="p-8 text-center text-gray-400">Please log in to view your profile.</div>;

  return (
    <div className="max-w-4xl mx-auto p-8 space-y-12 pb-20">
      {/* Profile Header */}
      <div className="flex flex-col md:flex-row items-center gap-8 bg-white/5 p-8 rounded-3xl border border-white/10 backdrop-blur-xl">
        <div className="w-24 h-24 bg-indigo-600 rounded-full flex items-center justify-center shadow-lg shadow-indigo-500/20">
          <User size={40} className="text-white" />
        </div>
        <div className="flex-grow text-center md:text-left space-y-2">
          {isEditingName ? (
            <div className="flex items-center gap-3 justify-center md:justify-start">
              <input 
                value={newName} 
                onChange={e => setNewName(e.target.value)}
                className="bg-black/40 border border-gray-700 rounded-lg px-4 py-1 text-white focus:ring-2 focus:ring-indigo-500 outline-none"
              />
              <button onClick={handleUpdateName} disabled={isLoading} className="p-2 bg-indigo-600 rounded-lg hover:bg-indigo-700 transition-colors">
                <Save size={18} />
              </button>
            </div>
          ) : (
            <div className="flex items-center gap-3 justify-center md:justify-start">
              <h1 className="text-3xl font-bold text-white mb-0">{user.name || 'Anonymous User'}</h1>
              <button onClick={() => setIsEditingName(true)} className="text-gray-500 hover:text-white transition-colors">
                <Edit2 size={18} />
              </button>
            </div>
          )}
          <p className="text-gray-400">{user.email}</p>
          <button onClick={logout} className="flex items-center gap-2 text-red-400 hover:text-red-300 transition-colors pt-2 mx-auto md:mx-0">
            <LogOut size={16} /> Sign Out
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Saved Favorites */}
        <div className="space-y-6">
          <h3 className="text-xl font-semibold flex items-center gap-2 text-white">
            <Heart className="text-pink-500 fill-pink-500" size={20} />
            Your Favorites
          </h3>
          <div className="space-y-3">
            {favorites.length === 0 ? (
              <p className="text-gray-500 text-sm italic">No favorites saved yet.</p>
            ) : (
              favorites.map(fav => (
                <div key={fav.id} className="flex items-center justify-between bg-white/5 p-4 rounded-xl border border-white/5 group hover:border-pink-500/30 transition-all">
                  <div>
                    <h4 className="font-medium text-white">{fav.title}</h4>
                    <span className="text-xs text-gray-500 uppercase tracking-widest">{fav.type}</span>
                  </div>
                  <button onClick={() => removeFavorite(fav.id)} className="text-gray-600 hover:text-red-400 transition-colors p-2">
                    <Heart size={18} className="fill-pink-500 text-pink-500 group-hover:fill-transparent" />
                  </button>
                </div>
              ))
            )}
          </div>
        </div>

        {/* Search History */}
        <div className="space-y-6">
          <h3 className="text-xl font-semibold flex items-center gap-2 text-white">
            <Clock className="text-indigo-400" size={20} />
            Recent Discoveries
          </h3>
          <div className="space-y-3">
            {history.length === 0 ? (
              <p className="text-gray-500 text-sm italic">Search history is empty.</p>
            ) : (
              history.map(item => (
                <div key={item.id} className="bg-white/5 p-4 rounded-xl border border-white/5 hover:border-indigo-500/30 transition-all">
                  <p className="text-sm text-indigo-300 mb-1">"{item.query}"</p>
                  <h4 className="font-medium text-white">{item.mainMatchTitle}</h4>
                  <span className="text-[10px] text-gray-500 uppercase">{new Date(item.createdAt).toLocaleDateString()}</span>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
